final:
module RefModule(
    input clk,
    input rst,
    output reg [2:0] out,
    output reg carry_out
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (rst) begin
            out <= 3'b0;
            carry_out <= 1'b0;
        end
        else if (out == 3'b111) begin
            out <= 3'b0;
            carry_out <= 1'b1;
        end
        else begin
            out <= out + 1;
            carry_out <= 1'b0;
        end
    end

endmodule
